function normalize(node) {
  return { label: node.l, catId: node.i, level: node.v, children: (node.k || []).map(normalize) };
}
const TAXONOMY = Object.fromEntries(
  Object.entries(RAW).map(([slug, cat]) => [
    slug, { heading: cat.heading, catId: cat.catId, children: cat.children.map(normalize) }
  ])
);
const CAT_KEYS = Object.keys(TAXONOMY);

// ─── SHARED STORAGE HELPERS ──────────────────────────────────────────────────
// Each category is stored independently so users don't overwrite each other.
// Key pattern: "bh:slots:{slug}" stored with shared=true

async function loadCatFromStorage(slug) {
  try {
    const res = await window.storage.get(`bh:slots:${slug}`, true);
    if (res) return JSON.parse(res.value);
  } catch {}
  return null;
}

async function saveCatToStorage(slug, slots, slotsL3, slotsL4, buyingGuideUrl, userName) {
  const payload = {
    slots,
    slotsL3,
    slotsL4,
    buyingGuideUrl: buyingGuideUrl || "",
    savedAt: Date.now(),
    savedBy: userName || "Anonymous"
  };
  try {
    await window.storage.set(`bh:slots:${slug}`, JSON.stringify(payload), true);
    return true;
  } catch { return false; }
}

function emptySlots() { return Array(30).fill(null); }

function initLocalState() {
  const out = {};
  CAT_KEYS.forEach(k => { out[k] = { slots: emptySlots(), slotsL3: {}, slotsL4: {}, buyingGuideUrl: "", savedAt: null, savedBy: null }; });
  return out;
}

