// ─── APPLICATIONS (RULE-BASED CATEGORY) ──────────────────────────────────────
// "Application" (catId 56954) is a cross-cutting bucket that sits at the top
// of the Category Taxonomy column for any L1 in APPLICATION_L1_KEYS. The
// parent node itself is NOT draggable; only its leaf children are.
// Children are level-3 categories but may be dropped into any slot level.
const APPLICATIONS = {
  catId: "56954",
  label: "Application",
  level: 2,
  groups: [
    {
      label: "Application - Photography",
      children: [
        { label: "Portrait Photography",             catId: "61959" },
        { label: "Wedding Photography",              catId: "62211" },
        { label: "Landscape Photography",            catId: "56817" },
        { label: "Wildlife Photography",             catId: "56888" },
        { label: "Macro Photography",                catId: "56887" },
        { label: "Astrophotography",                 catId: "56886" },
        { label: "Portrait and Studio Photography",  catId: "56889" }
      ]
    },
    {
      label: "Application - Video",
      children: [
        { label: "Intro to Cinema",   catId: "56891" },
        { label: "Content Creation",  catId: "56890" }
      ]
    }
  ]
};
const APPLICATION_L1_KEYS = new Set(["photography", "provideo"]);
// Flat list of Application leaf children, each pre-tagged with level 3 so
// the existing slot/render code treats them like any other L3 category.
const APPLICATION_CHILDREN = APPLICATIONS.groups.flatMap(g =>
  g.children.map(ch => ({ label: ch.label, catId: ch.catId, level: 3 }))
);


// Build lookup: catId → group label for a given slug
function buildGroupIndex(slug) {
  const index = {}; // catId → label (null = ungrouped intentionally)
  const order = []; // ordered list of { label, catIds } for rendering
  const seen = new Set();
  for (const g of (GROUPS[slug] || [])) {
    order.push(g);
    for (const id of g.catIds) { index[id] = g.label; seen.add(id); }
  }
  return { index, order, seen };
}

// ─── LEVEL STYLES ────────────────────────────────────────────────────────────
const LS = {
  2:     { dot: "#10b981", badge: "bg-emerald-50 text-emerald-700 border-emerald-200", label: "L2" },
  3:     { dot: "#3b82f6", badge: "bg-blue-50 text-blue-700 border-blue-200",         label: "L3" },
  4:     { dot: "#8b5cf6", badge: "bg-violet-50 text-violet-700 border-violet-200",   label: "L4" },
  5:     { dot: "#f59e0b", badge: "bg-amber-50 text-amber-700 border-amber-200",       label: "L5" },
  6:     { dot: "#ef4444", badge: "bg-red-50 text-red-700 border-red-200",             label: "L6" },
  7:     { dot: "#ec4899", badge: "bg-pink-50 text-pink-700 border-pink-200",          label: "L7" },
  label: { dot: "#64748b", badge: "bg-slate-100 text-slate-600 border-slate-300",     label: "LBL" },
};

function LevelBadge({ level }) {
  const s = LS[level] || LS[2];
  return (
    <span className={`inline-flex items-center gap-1 text-[10px] font-bold px-1.5 py-px rounded border ${s.badge} select-none flex-shrink-0`}>
      <span style={{ width:6, height:6, borderRadius:"50%", background:s.dot, display:"inline-block", flexShrink:0 }} />
      {s.label}
    </span>
  );
}

function timeAgo(ts) {
  if (!ts) return null;
  const s = Math.floor((Date.now() - ts) / 1000);
  if (s < 60) return "just now";
  if (s < 3600) return `${Math.floor(s/60)}m ago`;
  if (s < 86400) return `${Math.floor(s/3600)}h ago`;
  return `${Math.floor(s/86400)}d ago`;
}

// ─── TAXONOMY NODE ────────────────────────────────────────────────────────────
function TaxonomyNode({ item, depth, usedCatIds, onDragStart, onClickAdd }) {
  const [open, setOpen] = useState(false);
  const has = item.children && item.children.length > 0;
  const inSlot = usedCatIds.has(item.catId);
  const s = LS[item.level] || LS[2];

  return (
    <div>
      <div
        draggable={!inSlot}
        onDragStart={e => {
          if (inSlot) { e.preventDefault(); return; }
          e.dataTransfer.effectAllowed = "move";
          onDragStart({ label: item.label, catId: item.catId, level: item.level, explorerUrl: "" });
        }}
        className={`group flex items-center gap-1.5 py-[4px] pr-2 rounded transition-colors
          ${inSlot ? "opacity-40 cursor-default" : "hover:bg-gray-100 cursor-grab active:cursor-grabbing"}`}
        style={{ paddingLeft: 8 + depth * 12 }}
      >
        {has ? (
          <button onClick={() => setOpen(o => !o)}
            className="flex-shrink-0 flex items-center justify-center text-gray-400 hover:text-gray-600 rounded hover:bg-gray-200 transition-colors leading-none"
            style={{ fontSize:13, width:20, height:20, marginRight:1 }}>{open ? "▾" : "▸"}</button>
        ) : <span style={{ width:21, flexShrink:0, display:"inline-block" }} />}
        <span style={{ width:6, height:6, borderRadius:"50%", background:s.dot, display:"inline-block", flexShrink:0 }} />
        <span className={`flex-1 text-xs truncate ${inSlot ? "text-gray-400" : "text-gray-700 group-hover:text-gray-900"}`}
          style={{ fontSize: Math.max(10, 12 - (item.level - 2)) }}>
          {item.label}
        </span>
        <span className="text-[10px] text-gray-400 font-mono flex-shrink-0">{item.catId}</span>
        {inSlot
          ? <span className="text-[10px] text-emerald-500 flex-shrink-0 font-bold">✓</span>
          : <button onClick={() => onClickAdd({ label: item.label, catId: item.catId, level: item.level, explorerUrl: "" })}
              className="opacity-0 group-hover:opacity-100 text-[10px] text-gray-400 hover:text-blue-600 flex-shrink-0 px-1 rounded hover:bg-blue-50 transition-all font-bold"
              title="Add to next open slot">+</button>}
      </div>
      {has && open && (
        <div>
          {item.children.map(child => (
            <TaxonomyNode key={child.catId} item={child} depth={depth+1}
              usedCatIds={usedCatIds} onDragStart={onDragStart} onClickAdd={onClickAdd} />
          ))}
        </div>
      )}
    </div>
  );
}


// ─── APPLICATION NODE ────────────────────────────────────────────────────────
// Renders the cross-cutting "Application 56954" bucket in the taxonomy tree.
// The parent row and the per-group labels are non-draggable; only the leaf
